// LinkedIn job search URLs (HTML scrape — LinkedIn has no public RSS)
const searches = [
  { query: 'Customer+Success+Manager', location: 'India', geo: '102713980', label: 'CSM India' },
  { query: 'Project+Coordinator', location: 'India', geo: '102713980', label: 'PC India' },
  { query: 'Operations+Manager', location: 'Delhi+NCR', geo: '90009706', label: 'Ops Delhi' },
  { query: 'Business+Development+Manager', location: 'India', geo: '102713980', label: 'BDM India' },
  { query: 'Customer+Success+Manager', location: 'Europe', geo: '91000002', label: 'CSM Europe' },
  { query: 'Operations+Manager', location: 'Netherlands', geo: '102890719', label: 'Ops NL' },
  { query: 'Project+Manager', location: 'Germany', geo: '101282230', label: 'PM Germany' },
  { query: 'Business+Analyst', location: 'United+Kingdom', geo: '101165590', label: 'BA UK' }
];

const urls = searches.map(s => ({
  url: `https://www.linkedin.com/jobs-guest/jobs/api/seeMoreJobPostings/search?keywords=${s.query}&location=${s.location}&geoId=${s.geo}&f_TPR=r86400&start=0`,
  label: s.label,
  source_platform: s.label.includes('Europe') || s.label.includes('NL') || s.label.includes('Germany') || s.label.includes('UK') ? 'linkedin_eu' : 'linkedin_india'
}));

return urls.map(u => ({ json: u }));

const html = $input.first().json.data || $input.first().json;
const sourcePlatform = $('Build Search URLs').first().json.source_platform;

if (typeof html !== 'string') return [];

// Extract job cards from LinkedIn HTML
const jobMatches = html.match(/data-entity-urn="urn:li:jobPosting:(\d+)"/g) || [];
const titleMatches = html.match(/class="base-search-card__title"[^>]*>([^<]+)</g) || [];
const companyMatches = html.match(/class="base-search-card__subtitle"[^>]*>([^<]+)</g) || [];
const locationMatches = html.match(/class="job-search-card__location"[^>]*>([^<]+)</g) || [];

const jobs = [];
for (let i = 0; i < jobMatches.length; i++) {
  const idMatch = jobMatches[i].match(/(\d+)/);
  if (!idMatch) continue;
  const jobId = idMatch[1];
  const title = titleMatches[i] ? titleMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const company = companyMatches[i] ? companyMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const location = locationMatches[i] ? locationMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  jobs.push({
    job_id: jobId,
    job_title: title,
    company: company,
    location: location,
    job_url: `https://www.linkedin.com/jobs/view/${jobId}`,
    source_platform: sourcePlatform
  });
}

return jobs.map(j => ({ json: j }));

// Deduplicate using n8n static data
const seen = $getWorkflowStaticData('global');
if (!seen.linkedinSeenUrls) seen.linkedinSeenUrls = [];

const item = $input.first().json;
if (seen.linkedinSeenUrls.includes(item.job_url)) {
  return []; // Skip duplicate
}

seen.linkedinSeenUrls.push(item.job_url);
// Keep list from growing indefinitely
if (seen.linkedinSeenUrls.length > 2000) {
  seen.linkedinSeenUrls = seen.linkedinSeenUrls.slice(-1000);
}

return [{ json: item }];

const html = $input.first().json.data || '';
const prev = $('Deduplicate').first().json;

// Extract description text from LinkedIn job posting HTML
const descMatch = html.match(/class="show-more-less-html__markup[^"]*"[^>]*>([\s\S]*?)<\/div>/);
let description = '';
if (descMatch) {
  description = descMatch[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}

if (!description || description.length < 50) {
  description = `${prev.job_title} at ${prev.company}. See full description at: ${prev.job_url}`;
}

return [{ json: { ...prev, description: description.substring(0, 3000) } }];
